// Generated by AI (UnitTest MCP)

export type DesignStatus = "proposed" | "accepted" | "rejected";
export type DesignPromotionStatus = "not_required" | "pending" | "materialized";

export interface DesignItem {
  id: string;
  adr_path: string;
  title: string;
  summary: string;
  status: DesignStatus;
  proposed_by?: string | null;
  decided_by?: string | null;
  reason?: string | null;
  created_at: number;
  updated_at: number;
  promotion_status: DesignPromotionStatus;
  materialization_revision: number;
}

export interface DesignTask {
  id: string;
  goal_id: string;
  title: string;
  acceptance: string;
  status: string;
}

export interface DesignGoal {
  id: string;
  title: string;
  kind: string;
}

export interface DesignPromotion {
  item: DesignItem;
  mode: DesignMaterializationMode;
  revision: number;
  rationale?: string | null;
  goals: DesignGoal[];
  tasks: DesignTask[];
  constraints: DesignGoal[];
}

export type DesignMaterializationMode = "create" | "link" | "no_work";

export interface DesignTaskDraft {
  goal_id: string;
  title: string;
  acceptance: string;
}

export interface DesignConstraintDraft {
  kind: "constraint" | "invariant";
  title: string;
  statement: string;
}

export interface DesignMaterializationPlan {
  mode: DesignMaterializationMode;
  tasks?: DesignTaskDraft[];
  task_ids?: string[];
  constraints?: DesignConstraintDraft[];
  rationale?: string | null;
}

export interface DesignMaterializationRecord {
  design_id: string;
  revision: number;
  plan: DesignMaterializationPlan;
  actor: string;
  created_at: number;
}

export interface DesignMetadata {
  adr_path: string;
  title: string;
  summary: string;
  status: DesignStatus;
  proposed_by?: string;
}

export interface DesignBoardRow {
  id: string;
  label: string;
  description: string;
  tooltip: string;
  contextValue: string;
  item: DesignItem;
  promotion?: DesignPromotion;
}

const DESIGN_STATUS_ORDER: Record<string, number> = {
  proposed: 0,
  pending: 1,
  materialized: 2,
  historical: 3,
  rejected: 4,
};

export function parseAdrMetadata(
  adrPath: string,
  content: string,
  proposedBy?: string
): DesignMetadata | null {
  const normalizedPath = adrPath.replace(/\\/g, "/");
  const title = content.match(/^#\s+(.+?)\s*$/m)?.[1]?.trim();
  const statusText = content
    .match(/^\s*-?\s*(?:\*\*)?Status:(?:\*\*)?\s*([^\r\n]+)/im)?.[1]
    ?.replace(/\*/g, "")
    .trim()
    .toLowerCase();
  if (!title || !statusText || !isDesignStatus(statusText)) {
    return null;
  }
  return {
    adr_path: normalizedPath,
    title,
    summary: "",
    status: statusText,
    ...(proposedBy ? { proposed_by: proposedBy } : {}),
  };
}

export function designBoardRows(
  designs: DesignItem[],
  promotions: ReadonlyMap<string, DesignPromotion> = new Map()
): DesignBoardRow[] {
  return [...designs]
    .map((item) => toRow(item, promotions.get(item.id)))
    .sort((left, right) => {
      const statusDelta =
        (DESIGN_STATUS_ORDER[left.contextValue] ?? Number.MAX_SAFE_INTEGER) -
        (DESIGN_STATUS_ORDER[right.contextValue] ?? Number.MAX_SAFE_INTEGER);
      return (
        statusDelta ||
        left.item.created_at - right.item.created_at ||
        left.id.localeCompare(right.id)
      );
    });
}

export function designContext(item: DesignItem): string {
  if (item.status === "proposed") {
    return "proposed";
  }
  if (item.status === "rejected") {
    return "rejected";
  }
  if (item.promotion_status === "pending") {
    return "pending";
  }
  if (item.promotion_status === "materialized") {
    return "materialized";
  }
  return "historical";
}

export function replaceAdrStatus(content: string, status: DesignStatus): string | null {
  const pattern = /^(\s*-?\s*(?:\*\*)?Status:(?:\*\*)?\s*)([^\r\n]+)/im;
  if (!pattern.test(content)) {
    return null;
  }
  const label = status[0].toUpperCase() + status.slice(1);
  return content.replace(pattern, (_match, prefix: string) => `${prefix}${label}`);
}

export function formatMaterializationPlan(
  plan: DesignMaterializationPlan,
  linkedTasks: DesignTask[] = []
): string {
  const lines = [`Mode: ${plan.mode.replace("_", " ")}`];
  for (const task of plan.tasks ?? []) {
    lines.push(`Create: ${task.title} (${task.goal_id})`, `Done when: ${task.acceptance}`);
  }
  for (const taskId of plan.task_ids ?? []) {
    const task = linkedTasks.find((candidate) => candidate.id === taskId);
    lines.push(`Link: ${task ? `${task.title} (${task.id})` : taskId}`);
  }
  if (plan.rationale) {
    lines.push(`Rationale: ${plan.rationale}`);
  }
  return lines.join("\n");
}

export function formatDesignPromotion(
  promotion: DesignPromotion,
  history: DesignMaterializationRecord[] = []
): string {
  const objective =
    promotion.goals.length === 0
      ? "none"
      : promotion.goals.map((goal) => `${goal.title} (${goal.id})`).join(", ");
  const lines = [
    `# Design materialization: ${promotion.item.title}`,
    "",
    `- **ADR:** ${promotion.item.adr_path}`,
    `- **Mode:** ${promotion.mode}`,
    `- **Revision:** ${promotion.revision}`,
    `- **Objectives:** ${objective}`,
    `- **Tasks:** ${promotion.tasks.length}`,
    `- **Constraints:** ${promotion.constraints.length}`,
  ];
  if (promotion.rationale) {
    lines.push(`- **Rationale:** ${promotion.rationale}`);
  }
  if (promotion.tasks.length) {
    lines.push("", "## Tasks");
    for (const task of promotion.tasks) {
      lines.push(`- ${task.title} — ${task.status} (${task.id})`);
    }
  }
  if (promotion.constraints.length) {
    lines.push("", "## Constraints");
    for (const goal of promotion.constraints) {
      lines.push(`- ${goal.title} — ${goal.kind} (${goal.id})`);
    }
  }
  if (history.length) {
    lines.push("", "## Revision history");
    for (const record of history) {
      lines.push(
        `- r${record.revision} — ${record.plan.mode} by ${record.actor}: ${record.plan.rationale ?? "initial materialization"}`
      );
    }
  }
  return lines.join("\n");
}

function toRow(item: DesignItem, promotion?: DesignPromotion): DesignBoardRow {
  const contextValue = designContext(item);
  const details: string[] = [item.adr_path];
  if (item.summary) {
    details.push(item.summary);
  }
  if (item.proposed_by) {
    details.push(`proposed by: ${item.proposed_by}`);
  }
  if (item.decided_by) {
    details.push(`decided by: ${item.decided_by}`);
  }
  if (item.reason) {
    details.push(`reason: ${item.reason}`);
  }
  if (promotion) {
    for (const goal of promotion.goals) {
      details.push(`objective: ${goal.title} (${goal.id})`);
    }
    details.push(`mode: ${promotion.mode}; revision: ${promotion.revision}`);
    details.push(`tasks: ${promotion.tasks.length}; constraints: ${promotion.constraints.length}`);
  }
  return {
    id: item.id,
    label: item.title,
    description: describe(item, promotion),
    tooltip: details.join("\n"),
    contextValue,
    item,
    ...(promotion ? { promotion } : {}),
  };
}

function describe(item: DesignItem, promotion?: DesignPromotion): string {
  switch (designContext(item)) {
    case "proposed":
      return "proposed · review required";
    case "pending":
      return "accepted · promotion pending";
    case "materialized":
      return promotion?.mode === "no_work"
        ? `materialized · no new work · r${promotion.revision}`
        : `materialized · ${promotion?.tasks.length ?? 0} tasks · r${promotion?.revision ?? 0}`;
    case "rejected":
      return "rejected";
    default:
      return "accepted · historical";
  }
}

function isDesignStatus(value: string): value is DesignStatus {
  return value === "proposed" || value === "accepted" || value === "rejected";
}
